  ('elementary-0a2fc18c-moex-00703', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '有關比例原則之敘述，下列何者錯誤？', '["須採取之方法應有助於目的之達成", "多種同樣達成目的之方法中，須採取對人民權益損害最少者", "須採取之方法所造成之損害不得與欲達成目的之利益顯失均衡", "一行為違反數行政法上義務，應採取最輕之處罰規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00704', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列事項，何者不適用我國行政程序法之程序規定？', '["外交部與外國之建交行為", "撤銷進出口廠商營業登記之行為", "廢止土地徵收之行為", "再生能源發電設備生產電能躉購費率之審定行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00705', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於執行上級命令之行為不罰之敘述，何者錯誤？', '["明知上級公務員之命令為違法而執行之，不得阻卻違法", "以下達之命令為下級公務員之職務範圍內，始得主張阻卻違法", "下級公務員執行不符法定程式之命令，亦得阻卻違法", "命令之形式雖不以書面為限，但仍以具備法定程式為必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00706', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '人民申請換發汽車行車執照，卻遭公路監理機關以違規罰鍰尚未繳清為由，拒絕換發行車執照。此舉可 能違反下列何種行政上之一般法律原則？', '["不當聯結禁止原則", "比例原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00707', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '有關損失補償之敘述，下列何者錯誤？', '["因公益而特別犧牲財產上之利益，國家應依法律規定辦理補償", "損失補償是針對國家的合法行為而干預人民之財產權所生之填補措施", "現行法下，行政徵收不以公用之目的為限", "基於平等原則，只要國家對財產權有所限制，即應給予補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00708', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '有關公共設施國家賠償責任的敘述，下列何者錯誤？', '["須賠償義務機關有故意或過失，始成立國家賠償責任", "公共設施委託民間團體管理，因管理欠缺導致人民人身自由或財產受有損害，國家亦負賠償責任", "於開放山域的自然公物，經管理機關對公物為適當的警告或標示，人民仍從事冒險或具危險性活動而 受有損害，國家不負賠償責任", "建築中的公共設施未開放公用，即非屬公共設施"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00709', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於民事訴訟上當事人能力之敘述，何者正確？', '["當事人能力為訴訟成立要件之一，若當事人欠缺當事人能力，法院應逕行以訴不合法裁定駁回其訴", "非法人團體因不具權利能力，因此不具有當事人能力", "無當事人能力人所為之訴訟行為，其效力得經取得能力之人承認而治癒", "當事人於訴訟中死亡時，法院應即以當事人能力有欠缺而裁定駁回其訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00710', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於行政罰的敘述，何者錯誤？', '["違反行政法上義務之行為，以處罰故意為原則，過失行為之處罰以法律有明文規定為限", "滿十四歲以上，未滿十八歲人之行為，得減輕處罰", "不得因不知法規而免除行政處罰責任", "違反行政法上義務之行為非出於故意或過失者，不予處罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00711', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列行政訴訟法所定之訴訟種類，何者非以行政處分為程序標的？', '["撤銷訴訟", "申請遭否准之訴訟", "怠為處分訴訟", "一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00712', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列有關訴願要件之敘述，何者錯誤？', '["除行政處分違法外，行政處分不當亦得提起訴願", "訴願的對象尚包括消極的不作為", "一律以原處分機關為受理訴願機關", "須以權利或法律上利益遭受侵害為前提"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
